code.C:
#include <stdio.h>
#include <stdlib.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long a;
        if(scanf("%lld",&a)!=1) break;
        long long square=a*a;
        long long cube=a*a*a;
        printf("Square is: %lld\n",square);
        printf("Cube is: %lld\n",cube);
    }
    return 0;
}

